obj.getRoomTiles=function(view,roomX,roomY,tileset){
  var created=true;
  var found=-1;
  var found2=-1; 
  
  if(jte.tiles!=undefined){
   	if(jte.tiles[view]!=undefined){
      
      for(var i=0;i<jte.tiles[view].length;i++){
       	var tiles=jte.tiles[view][i]; 
        if(tiles.x==roomX && tiles.y==roomY){
          //found
          found=i;
          if(tiles.tilesets!=undefined){
           	
            for(var j=0;j<tiles.tilesets.length;j++){
               if(tiles.tilesets[j].img==tileset){
                 found2=j;
                 return jte.tiles[view][i].tilesets[j];	
               }
             }
            if(found2==-1){
             	created=false; 
            }
          }else{
           	created=false; 
          }
          break;
        }
        
        if(!created){
         	break; 
        }
      }
      
      if(found==-1){
       	created=false; 
      }
    }else{
     	created=false; 
    }
  }else{
   	created =false;
  }
  
  var createAll=false;
  
  if(!created){
   	if(found>=0){
     	if(found2>=0){
        jte.tiles[view][found].tilesets[found2]={img:tileset,unit:16,tiles:[]};
      	return jte.tiles[view][found].tilesets[found2];
      }else{
        jte.tiles[view][found].tilesets.push({img:tileset,unit:16,tiles:[]})
      	return jte.tiles[view][found].tilesets[jte.tiles[view][found].tilesets.length-1];
      }
    }else{
      createAll=true;
    }
  }
  
  jte.tiles[view].push({x:roomX,y:roomY,tilesets:[{img:tileset,unit:16,tiles:[]}]});
  return jte.tiles[view][jte.tiles[view].length-1].tilesets[0];
}



