obj.spriteOffset=2;
obj.spriteOffsetBig=4;

obj.addProjectile=function(proj,activatedAgain){
  var client=jt.getObject("Client");
  if(client.isGuard || jt.getView()=="Tutorial"){
    var so=this.spriteOffset;
    if(proj.w>=32 || proj.h>=32){so=this.spriteOffsetBig}
    proj.x+=so;
    proj.y+=so;    
    proj.w-=so*2;        
    proj.h-=so*2;     
    if(activatedAgain!=undefined){proj.player=activatedAgain;}
    var attrs=this.getProjectileAttrs(proj.id);
    if(attrs.sprite!=undefined){
     	 if(jt.anims()[attrs.sprite]!=undefined){
        	jt.animFrame(attrs.sprite,0); 
       }
    }
  	client.clientObj.projectiles.push(proj);
  }
}

