//Tags and alpha changes
obj.removeTag=function(name,tag,record){
  if(record==undefined){record=true;}
  var object=jt.getObject(name);
  
  var index=object.tags.indexOf(tag);
  if(index>=0){
   	object.tags.splice(index,1); 
  }
  
  if(record){
   	this.changesName.push(name);
    this.changesRemoveTag.push(tag);
    this.changesAddTag.push(undefined);    
    this.changesAlpha.push(undefined);        
  }
}

obj.addTag=function(name,tag,record){
  if(record==undefined){record=true;}
  var object=jt.getObject(name);
  
  object.tags.push(tag);
  
  if(record){
   	this.changesName.push(name);
    this.changesRemoveTag.push(undefined);
    this.changesAddTag.push(tag);    
    this.changesAlpha.push(undefined);        
  }
}

obj.setAlpha=function(name,alpha,record){
  if(record==undefined){record=true;}
  var object=jt.getObject(name);
  
  var before=object.alpha;
  
  object.alpha=alpha;
  
  if(record){
   	this.changesName.push(name);
    this.changesRemoveTag.push(undefined);
    this.changesAddTag.push(undefined);    
    this.changesAlpha.push(before);        
  }
}

