obj.restart=function(){ 
  this.teleport=false;
  
  var client=jt.getObject("Client");
  
  client.wonIds=[];
  
  client.clientObj.projectiles=[];  
  this.respawn(false);
  client.clientObj.projectiles=[];
  
  
  client.clientObj.state="";
  
  this.barrierTimer=this.barrierTimerMax;
  
  this.timerMax=this.getMapTime(client.nextView);
  this.timer=this.timerMax;
}

obj.respawn=function(dead,killer){
  //this.powerupTimer=0;
  if(dead==undefined){dead=false;}
  var client=jt.getObject("Client");
  
  var viewId=client.nextView.toLowerCase();
  
  this.invincibleTimer=this.invincibleTimerMax;
  
  this.actionTimer=0;
  
  /*
  client.clientObj.x=map.spawns[client.index].x+map.ts/2-this.playerW/2; 
  
  client.clientObj.y=map.spawns[client.index].y+map.ts/2-this.playerH/2;
  
  client.clientObj.r=map.spawns[client.index].r;
  */
  
  var spawnRunner=jt.getObjects(["SpawnRunner"],client.nextView)[0];
  var spawnGuard=jt.getObjects(["SpawnGuard"],client.nextView)[0];  
  
  if(client.isGuard){
    client.clientObj.x=spawnGuard.x;
    client.clientObj.y=spawnGuard.y;    
  }else{
    client.clientObj.x=spawnRunner.x;
    client.clientObj.y=spawnRunner.y; 
  }
  
  this.crouch=false;
  client.clientObj.w=this.playerW;
  client.clientObj.h=this.playerH; 
  
  this.vX=0;
  this.vY=0;  
  
  this.dir=1;
  
  this.respawnX=client.clientObj.x;
  this.respawnY=client.clientObj.y;  
  
  if(dead){
    jt.stopPlay("characterSoundHurt");
    client.clientObj.x=999;
    client.clientObj.y=999;  
    if(client.isGuard){
      jt.stopPlay(viewId+"SoundLose")
      if(killer==undefined){
       	killer=jt.choose(client.withs); 
      }
      client.runnerWin(killer);
    }else{
     	//runner respawn 
      this.respawnTimer=this.respawnTimerMax;
      this.invincibleTimer+=this.respawnTimerMax;
    }
  }
}

