obj.getRainbow=function(ratio,alpha){
  if(alpha==undefined){alpha=1;}
  var r=jt.waveYPos(ratio);
  var g=jt.waveYPos(ratio+0.33);
  var b=jt.waveYPos(ratio+0.66);
  return [255*r,255*g,255*b,alpha];
}

obj.drawPlayer=function(player){ 
  var character=player.character;
  var anim=player.anim;  
  jt.alpha(1)
  
  var sprite="character"+character+anim;
  
  if(player.dir==-1){
  	jt.scale(-1,1,player.x,player.y,player.w,player.h)
  }
  
  if(jt.anims()[sprite]!=undefined){
    jt.anim(sprite,player.x+player.w/2-16,player.y+player.h-32,32,32);
  }else{
    jt.image(sprite,player.x+player.w/2-16,player.y+player.h-32,32,32);
  }
  
  //Draw accessory
  if(player.state!=""){
    var client=jt.getObject("Client");
   	var map=client.nextView.toLowerCase();
    if(client.nextView=="Tutorial"){map="castle";}
    var accessory=map+"Accessory";
    
    var w=16;
    var h=16;
    
    var x=player.x+player.w/2-w/2;
    var y=player.y-2;
    var offset=0;
    
    if(anim=="Jump"){
      offset=-2;
    }else if(anim=="Walk"){
      if(jt.animFrame(sprite)==0 || jt.animFrame(sprite)==1){
       	offset=-2; 
      }
    }else if(anim=="Crouch"){
      offset=-3;
    }
    
    jt.image(accessory,x,y+offset,w,h);
  }
  
  if(player.dir==-1){
  	jt.scale(-1,1,player.x,player.y,player.w,player.h)
  }
}

obj.getProjectileAttrs=function(id){
  var attrs=this.projectileAttrs[id];
  if(attrs==undefined){
    var keys=Object.keys(this.projectileAttrs);
    var len=Object.keys(this.projectileAttrs).length;
    for (var j = 0; j < len; j++){
      if(id.indexOf(keys[j])!=-1){
        attrs=this.projectileAttrs[keys[j]];
      }
    }
  } 
  return attrs;
}

obj.drawProjectile=function(projectile,noOffset){
  var attrs=this.getProjectileAttrs(projectile.id);
  var so=this.spriteOffset;
  if(projectile.w>=32 || projectile.h>=32){so=this.spriteOffsetBig}
  
  if(noOffset!=undefined || projectile.noOffset!=undefined){
    so=0;
  }
  
  if(projectile.dir!=undefined){
    if(projectile.dir<0){
  		jt.scale(-1,1,projectile.x,projectile.y,projectile.w,projectile.h)
    }
  }
  
  var r=0;
  if(projectile.r!=undefined){r=projectile.r;}
  
  var sprite=attrs.sprite;
  if(sprite!=undefined){
    if(jt.anims()[sprite]!=undefined){
      if(sprite=="castleFireHorizontal" && projectile.w<projectile.h){sprite="castleFireVertical";}
      jt.anim(sprite,projectile.x-so,projectile.y-so,projectile.w+so*2,projectile.h+so*2,r)
    }else{
      jt.image(sprite,projectile.x-so,projectile.y-so,projectile.w+so*2,projectile.h+so*2,r)
    }
  }else{
    jt.rect(projectile.x-so,projectile.y-so,projectile.w+so*2,projectile.h+so*2,"red",r); 
  }
  if(jt.debug()){
   	jt.rect(projectile.x,projectile.y,projectile.w,projectile.h,[255,0,0,0.5]);  
  }
  
  if(projectile.dir!=undefined){
    if(projectile.dir<0){
  		jt.scale(-1,1,projectile.x,projectile.y,projectile.w,projectile.h)
    }
  }
}

