obj.changeRound=function(){
  var client=jt.getObject("Client");
  var viewId=client.nextView.toLowerCase();
  
  //Reset all traps
  for(var i=0;i<this.hidesId.length;i++){
   	 this.showHide(this.hidesId[i]);
  }
  
  var weapons=jt.getObjects(["Weapon"]);
  for(var i=0;i<weapons.length;i++){
    weapons[i].alpha=1;
  }
  
  //Change all cooldown back
  var keys=Object.keys(this.cooldowns);
  var len=Object.keys(this.cooldowns).length;
  for (var i = 0; i < len; i++) {
    var btns=jt.getObjects(["Button",keys[i]],client.nextView,true);
    if(btns.length>0){
      btns[0].alpha=1;
    }
    this.cooldowns[keys[i]]=0;
  }
  
  //Changes all objects back
  for(var i=this.changesName.length-1;i>=0;i--){
    var name=this.changesName[i];
    //var object=jt.getObject(name);
    
    if(this.changesRemoveTag[i]!=undefined){
     	 this.addTag(name,this.changesRemoveTag[i],false)
    }
    
    if(this.changesAddTag[i]!=undefined){
     	 this.removeTag(name,this.changesAddTag[i],false)
    }
    
    if(this.changesAlpha[i]!=undefined){
     	 this.setAlpha(name,this.changesAlpha[i],false)
    }
  }
  
  this.changesName=[];
  this.changesRemoveTag=[];  
  this.changesAddTag=[];    
  this.changesAlpha=[];      
  
  this.hides=[]
  this.hidesId=[]  
  this.delays=[]    
  this.delaysId=[]    
  this.delaysCpt=[]      
  
  
  //Change round
 	client.started=false; 
  client.waitTime=client.waitSecond*60; 
  jt.setView("Loading");
  jt.stop(viewId+"Music");
  
  client.nextView=this.nextMap;
  
  client.clientObj.projectiles=[];
  client.powerups=[];
  
  if(client.index==0){
    	//jt.getObject("Map").generate();
      //jt.getObject("Client").sendMap();
    
  }else{
   	//jt.getObject("Game").restart(); 
  }
}

