obj.drawMiniMap=function(square,view){
 	//Draw mini map
  var client=jt.getObject("Client");
  
  var walls=jt.getObjects(["Wall"],view);
  var deaths=jt.getObjects(["Death"],view);      
  var throughs=jt.getObjects(["Through"],view); 
  var destroys=jt.getObjects(["Destroy"],view);   

  var spawnRunner=jt.getObjects(["SpawnRunner"],view);                  
  var spawnGuard=jt.getObjects(["SpawnGuard"],view);
  
  var teleports=jt.getObjects(["Teleport1","Teleport2"],view,false);    

  var mapRatio=square.w/jt.w();

  for(var i=0;i<walls.length;i++){
    var wall=walls[i];
    if(wall.tags.indexOf("Destroy")!=-1 || wall.tags.indexOf("Barrier")!=-1){continue;}
    var xx=(wall.x*mapRatio)+square.x;
    var yy=(wall.y*mapRatio)+square.y;        
    var ww=(wall.w*mapRatio);                
    var hh=(wall.h*mapRatio);                        
    jt.rect(xx,yy,ww,hh,"black");
  }

  for(var i=0;i<deaths.length;i++){
    var death=deaths[i];
    var xx=(death.x*mapRatio)+square.x;
    var yy=(death.y*mapRatio)+square.y;        
    var ww=(death.w*mapRatio);                
    var hh=(death.h*mapRatio);                        
    jt.rect(xx,yy,ww,hh,"red");
  }

  for(var i=0;i<throughs.length;i++){
    var through=throughs[i];
    var xx=(through.x*mapRatio)+square.x;
    var yy=(through.y*mapRatio)+square.y;        
    var ww=(through.w*mapRatio);                
    var hh=(through.h*mapRatio);                        
    jt.rect(xx,yy,ww,hh,"black");
  }
  
  for(var i=0;i<teleports.length;i++){
    var teleport=teleports[i];
    var xx=(teleport.x*mapRatio)+square.x;
    var yy=(teleport.y*mapRatio)+square.y;        
    var ww=(teleport.w*mapRatio);                
    var hh=(teleport.h*mapRatio);                        
    jt.rect(xx,yy,ww,hh,[0,0,255]);
  }
  
  for(var i=0;i<destroys.length;i++){
    var destroy=destroys[i];
    var xx=(destroy.x*mapRatio)+square.x;
    var yy=(destroy.y*mapRatio)+square.y;        
    var ww=(destroy.w*mapRatio);                
    var hh=(destroy.h*mapRatio);                        
    jt.rect(xx,yy,ww,hh,"orange");
  }
  
  var flashing=false;
  if(jt.frames()%30<=15){
   	flashing=true; 
  }
  
  if(client.isGuard && flashing){
    for(var i=0;i<spawnGuard.length;i++){
      var spawn=spawnGuard[i];
      var xx=(spawn.x*mapRatio)+square.x;
      var yy=(spawn.y*mapRatio)+square.y;        
      var ww=(spawn.w*mapRatio);                
      var hh=(spawn.h*mapRatio);                        
      jt.rect(xx,yy,ww,hh,"white");
    } 
  }else if(!client.isGuard && flashing){
    for(var i=0;i<spawnRunner.length;i++){
      var spawn=spawnRunner[i];
      var xx=(spawn.x*mapRatio)+square.x;
      var yy=(spawn.y*mapRatio)+square.y;        
      var ww=(spawn.w*mapRatio);                
      var hh=(spawn.h*mapRatio);                        
      jt.rect(xx,yy,ww,hh,"white");
    }
  }

}

